class Solution {
    public char kthCharacter(long k, int[] operations) {
        long n = 1;
        for (int op : operations) {
            if (op == 0) {
                k %= (n *= 2);
            } else {
                k = (k + n - 1) / n * n + (k + n - 1) % n;
            }
        }
        return (char) ('a' + (k - 1) % 26);
    }
}
